/* ── TOKENS & BASE ────────────────────────────────────── */
:root {
  --bg: #f5f7fa;
  --surface: #ffffff;
  --surface-2: #f0f4f8;
  --border: #e2e8f0;
  --accent: #1d6fa4;
  --accent-light: rgba(29,111,164,0.08);
  --text-main: #1a2433;
  --text-sub: #5a6a7e;
  --text-muted: #9aaab8;
  --green: #15803d;
  --yellow: #b45309;
  --red: #b91c1c;
  --green-bg: rgba(21,128,61,0.08);
  --yellow-bg: rgba(180,83,9,0.08);
  --red-bg: rgba(185,28,28,0.08);
  --green-border: rgba(21,128,61,0.25);
  --yellow-border: rgba(180,83,9,0.25);
  --red-border: rgba(185,28,28,0.25);
  --font-mono: "Share Tech Mono", monospace;
  --font-ui: "Barlow Condensed", sans-serif;
  --shadow-sm: 0 1px 3px rgba(0,0,0,0.06), 0 1px 2px rgba(0,0,0,0.04);
  --shadow-md: 0 4px 12px rgba(0,0,0,0.07), 0 2px 4px rgba(0,0,0,0.04);
}

*, *::before, *::after {
  box-sizing: border-box;
}

html, body {
  margin: 0;
  padding: 0;
  width: 100%;
  height: 100%;
  background: var(--bg);
  font-family: var(--font-ui);
  color: var(--text-main);
}

body {
  padding: 24px;
}

.dashboard-wrapper {
  width: 100%;
  max-width: 1200px;
  margin: 0 auto;
}

.section-gap {
  margin-bottom: 24px;
}

/* ── SHARED COMPONENTS ────────────────────────────────── */
.panel {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 24px;
  box-shadow: var(--shadow-sm);
  width: 100%;
}

.panel-header {
  text-align: center;
  margin-bottom: 24px;
}

.panel-header h2 {
  font-family: var(--font-ui);
  font-size: 39px;
  font-weight: 700;
  letter-spacing: 2px;
  text-transform: uppercase;
  margin: 0 0 6px;
}

.panel-header p {
  font-family: var(--font-mono);
  font-size: 20px;
  color: var(--text-sub);
  margin: 0 0 20px;
}

.header-rule {
  width: 140px;
  height: 2px;
  margin: 0 auto;
  background: linear-gradient(90deg, transparent, var(--accent), transparent);
  border-radius: 2px;
}

.status-pill {
  display: inline-block;
  font-family: var(--font-ui);
  font-size: 20px;
  font-weight: 600;
  letter-spacing: 0.8px;
  text-transform: uppercase;
  padding: 5px 16px;
  border-radius: 20px;
  background: var(--surface-2);
  color: var(--text-muted);
  border: 1px solid var(--border);
  transition: all 0.3s ease;
}

.status-pill.ok {
  background: var(--green-bg);
  color: var(--green);
  border-color: var(--green-border);
}

.status-pill.warn {
  background: var(--yellow-bg);
  color: var(--yellow);
  border-color: var(--yellow-border);
}

.status-pill.critical {
  background: var(--red-bg);
  color: var(--red);
  border-color: var(--red-border);
}

/* ── 1. MAIN HEADER ───────────────────────────────────── */
.main-header {
  text-align: center;
  margin-bottom: 36px;
}

.main-header h1 {
  font-size: 50px;
  font-weight: 700;
  letter-spacing: 3px;
  text-transform: uppercase;
  margin: 0 0 12px;
}

.subtitle {
  font-family: var(--font-mono);
  font-size: 20px;
  color: var(--text-sub);
  margin: 0 0 20px;
}

/* ── 2. METRICS ROW ───────────────────────────────────── */
.metrics-row {
  display: flex;
  gap: 16px;
  width: 100%;
}

.pulse-card {
  flex: 1;
  background: var(--surface);
  border: 1px solid var(--border);
  border-top: 3px solid var(--accent);
  padding: 26px 18px 22px;
  border-radius: 8px;
  text-align: center;
  box-shadow: var(--shadow-sm);
  transition: transform 0.2s, box-shadow 0.2s;
}

.pulse-card:hover {
  box-shadow: var(--shadow-md);
  transform: translateY(-2px);
}

.pulse-card label {
  display: block;
  font-size: 18px;
  font-weight: 600;
  color: var(--text-sub);
  text-transform: uppercase;
  letter-spacing: 1.4px;
  margin-bottom: 12px;
}

.pulse-card .val {
  font-family: var(--font-mono);
  font-size: 59px;
  color: var(--accent);
  line-height: 1;
}

/* ── 3. BOUNDARY GRID ─────────────────────────────────── */
.boundary-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 16px;
}

.b-card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 26px 16px 22px;
  text-align: center;
  box-shadow: var(--shadow-sm);
  transition: transform 0.2s;
}

.b-card:hover {
  box-shadow: var(--shadow-md);
  transform: translateY(-2px);
}

.b-label {
  display: block;
  font-size: 18px;
  font-weight: 600;
  color: var(--text-sub);
  text-transform: uppercase;
  margin-bottom: 16px;
}

.donut-wrap {
  position: relative;
  width: 110px;
  height: 110px;
  margin: 0 auto 14px;
}

.donut-svg {
  width: 110px;
  height: 110px;
  transform: rotate(-90deg);
  display: block;
}

.donut-track {
  fill: none;
  stroke: #e9eef4;
  stroke-width: 9;
}

.donut-fill {
  fill: none;
  stroke-width: 9;
  stroke-linecap: round;
  stroke: var(--green);
  transition: stroke-dasharray 0.9s cubic-bezier(0.4, 0, 0.2, 1), stroke 0.5s;
}

.donut-center {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  font-family: var(--font-mono);
  font-size: 35px;
  line-height: 1;
  pointer-events: none;
}

/* ── 4 & 5. DELTA & DRIFT BADGES ──────────────────────── */
.delta-main, .drift-stats {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 40px;
  margin-bottom: 24px;
}

.drift-stats {
  gap: 20px;
}

.badge-card {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 10px;
  padding: 28px 16px;
  border-radius: 12px;
  border: 1px solid var(--border);
  background: var(--surface-2);
  text-align: center;
  transition: transform 0.2s;
}

.badge-card:hover {
  transform: translateY(-2px);
  box-shadow: var(--shadow-md);
}

#delta-badge-card {
  flex: 0 0 200px;
}

.badge-card.neutral {
  background: var(--surface-2);
  border-color: var(--border);
}

.badge-card.danger {
  background: var(--red-bg);
  border-color: var(--red-border);
}

.badge-card.warn {
  background: var(--yellow-bg);
  border-color: var(--yellow-border);
}

.badge-card.ok {
  background: var(--green-bg);
  border-color: var(--green-border);
}

.b-val {
  font-family: var(--font-mono);
  font-size: 48px;
  font-weight: 800;
  line-height: 1;
}

.b-val small {
  font-size: 20px;
  color: var(--text-muted);
  font-weight: 400;
}

.danger-text {
  color: var(--red);
}

.warn-text {
  color: var(--yellow);
}

.badge-card label {
  font-size: 15px;
  font-weight: 600;
  color: var(--text-sub);
  text-transform: uppercase;
  letter-spacing: 1.2px;
}

/* ── 4. BAR CHART ─────────────────────────────────────── */
.trend-visualization {
  flex: 1;
  display: flex;
  justify-content: center;
}

.bar-chart {
  display: flex;
  align-items: flex-end;
  justify-content: center;
  gap: 40px;
  height: 140px;
  border-bottom: 2px solid var(--border);
}

.bar-wrap {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
  height: 100%;
  justify-content: flex-end;
}

.bar {
  width: 64px;
  border-radius: 6px 6px 0 0;
  transition: background-color 0.4s, height 0.6s ease;
}

.bar.prev {
  height: 100%;
  background: var(--border);
}

.bar.curr {
  height: 55%;
  background: var(--red);
}

.bar-label {
  font-size: 15px;
  font-weight: 600;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.8px;
}

.panel-footer {
  padding-top: 16px;
  border-top: 1px solid var(--border);
  font-size: 18px;
  color: var(--text-sub);
}

/* ── 5. DRIFT TABLE ───────────────────────────────────── */
.table-wrapper table {
  width: 100%;
  border-collapse: collapse;
}

.table-wrapper th {
  text-align: left;
  font-size: 15px;
  font-weight: 600;
  color: var(--text-muted);
  text-transform: uppercase;
  padding-bottom: 10px;
  border-bottom: 1px solid var(--border);
}

.table-wrapper td {
  padding: 14px 0;
  border-bottom: 1px solid var(--border);
  font-size: 18px;
}

.badge-unsupported {
  font-family: var(--font-mono);
  font-size: 14px;
  font-weight: 600;
  padding: 4px 10px;
  border-radius: 3px;
  background: var(--red-bg);
  color: var(--red);
  border: 1px solid var(--red-border);
  text-transform: uppercase;
}

/* ── 6. PRIORITY BOX ──────────────────────────────────── */
.priority-box {
  border-left: 4px solid var(--red);
}

.priority-header {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 18px;
}

.priority-icon {
  font-size: 25px;
  color: var(--red);
}

.priority-header h3 {
  margin: 0;
  font-size: 22px;
  font-weight: 700;
  letter-spacing: 1.5px;
  text-transform: uppercase;
  color: var(--red);
}

#signal-list {
  margin: 0;
  padding: 0;
  list-style: none;
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.signal-item {
  display: flex;
  align-items: flex-start;
  gap: 14px;
  padding: 14px 18px;
  border-radius: 6px;
  background: var(--surface-2);
  border: 1px solid var(--border);
  font-size: 21px;
}

.signal-badge {
  flex-shrink: 0;
  font-family: var(--font-mono);
  font-size: 15px;
  font-weight: 600;
  padding: 4px 12px;
  border-radius: 3px;
  text-transform: uppercase;
}

.signal-badge.critical {
  background: var(--red-bg);
  color: var(--red);
  border: 1px solid var(--red-border);
}

.signal-badge.high {
  background: var(--yellow-bg);
  color: var(--yellow);
  border: 1px solid var(--yellow-border);
}

.signal-badge.warning {
  background: var(--accent-light);
  color: var(--accent);
  border: 1px solid rgba(29, 111, 164, 0.25);
}

.signal-text {
  font-size: 21px;
}

