/* ── UI HELPERS ──────────────────────────────────────────── */
function setVal(id, val) {
  const el = document.getElementById(id);
  if (el) el.textContent = val;
}

function setPill(id, text, state) {
  const el = document.getElementById(id);
  if (!el) return;
  el.textContent = text;
  el.className = 'status-pill ' + state;
}

function drawDonut(id, val, max, colorOverride) {
  const circ = 2 * Math.PI * 46; // Circumference for r=46
  const el = document.getElementById(id);
  if (!el) return;

  const pct = max > 0 ? Math.min(val / max, 1) : 0;
  el.style.strokeDasharray = `${pct * circ} ${circ}`;

  if (colorOverride) {
    el.style.stroke = colorOverride;
  } else {
    if (pct === 0) el.style.stroke = 'var(--green)';
    else if (pct < 0.5) el.style.stroke = 'var(--yellow)';
    else el.style.stroke = 'var(--red)';
  }
}

/* ── MAIN DASHBOARD RENDER ───────────────────────────────── */
function updateDashboard() {
  const model = (typeof appsmith !== 'undefined' && appsmith.model.current) ? appsmith.model : { current: {}, meta: { baseline: 49, currentScore: 48 } };
  const current = model.current || {};
  const meta = model.meta || {};
  const codeSum = current.code?.components?.summary?.by_type || {};

  /* 1. TOP METRICS */
  const totalAiSystems = (codeSum?.llm_sdk?.count || 0) + (codeSum?.llm_framework?.count || 0);

  const logs = Array.isArray(current.web) ? current.web : [];
  const domains = new Set();
  logs.forEach(entry => {
    const url = entry.params?.request?.url || entry.url;
    if (url && url.startsWith('http')) {
      try { domains.add(new URL(url).hostname); } catch (e) {}
    }
  });
  const endpointsCount = domains.size;

  const integrations = Object.keys(current.code?.components?.summary?.by_provider || {}).length;
  const totalWorkflows = (codeSum?.agent?.count || 0) + (codeSum?.rag?.count || 0);

  setVal('val-systems', totalAiSystems);
  setVal('val-endpoints', endpointsCount);
  setVal('val-integrations', integrations);
  setVal('val-workflows', totalWorkflows);

  /* 2. BOUNDARY RISKS */
  const dataRisks = current.modelGov?.length || 23;
  setVal('b-data-val', dataRisks);
  drawDonut('donut-data', dataRisks, 50, dataRisks > 10 ? 'var(--red)' : dataRisks > 0 ? 'var(--yellow)' : 'var(--green)');
  setPill('b-data-status', dataRisks > 0 ? '↑ Critical Exposure' : 'Aligned', dataRisks > 0 ? 'critical' : 'ok');

  const modelRisks = codeSum?.model_artifact?.count || 12;
  setVal('b-model-val', modelRisks);
  drawDonut('donut-model', modelRisks, 30, modelRisks > 5 ? 'var(--red)' : modelRisks > 0 ? 'var(--yellow)' : 'var(--green)');
  setPill('b-model-status', modelRisks > 0 ? '↑ Untrusted Assets' : 'Verified', modelRisks > 0 ? 'critical' : 'ok');

  const sysRisks = current.code?.cross_file?.ai_boundaries || 2;
  setVal('b-system-val', sysRisks);
  drawDonut('donut-system', sysRisks, 20, sysRisks > 5 ? 'var(--red)' : sysRisks > 0 ? 'var(--yellow)' : 'var(--green)');
  setPill('b-system-status', sysRisks === 0 ? 'Stable Paths' : 'Crossing Detected', sysRisks > 0 ? 'warn' : 'ok');

  const enterpriseScore = meta.currentScore || 48;
  const baselineScore = meta.baseline || 49;
  setVal('b-enterprise-val', `${enterpriseScore}/100`);
  drawDonut('donut-enterprise', enterpriseScore, 100, enterpriseScore < baselineScore ? 'var(--yellow)' : 'var(--green)');
  setPill('b-enterprise-status', enterpriseScore < baselineScore ? 'Degraded' : 'Stable', enterpriseScore < baselineScore ? 'warn' : 'ok');

  /* 3. EXECUTION RISK DELTA */
  const diff = enterpriseScore - baselineScore;
  const deltaPill = document.getElementById('delta-indicator');
  const deltaMsg = document.getElementById('delta-message');
  const currBar = document.getElementById('bar-current');
  const deltaCard = document.getElementById('delta-badge-card');

  document.getElementById('delta-value-display').innerHTML = `${enterpriseScore}<small>/100</small>`;
  document.getElementById('label-baseline').textContent = `Baseline (${baselineScore})`;
  document.getElementById('label-current').textContent = `Current (${enterpriseScore})`;

  if (diff < 0) {
    deltaPill.textContent = `Regressed (${diff})`;
    deltaPill.className = 'status-pill critical';
    deltaCard.className = 'badge-card danger';
    if (currBar) { currBar.style.backgroundColor = 'var(--red)'; currBar.style.height = '45%'; }
    deltaMsg.innerHTML = `⚠️ <strong>Risk Increase:</strong> Security posture has regressed by ${Math.abs(diff)} pt since the last baseline scan.`;
  } else if (diff > 0) {
    deltaPill.textContent = `Improved (+${diff})`;
    deltaPill.className = 'status-pill ok';
    deltaCard.className = 'badge-card ok';
    if (currBar) { currBar.style.backgroundColor = 'var(--green)'; currBar.style.height = '100%'; }
    deltaMsg.innerHTML = `✅ <strong>Posture Improvement:</strong> Remediation efforts have increased the safety score by ${diff} pt.`;
  } else {
    deltaPill.textContent = 'Stable';
    deltaPill.className = 'status-pill warn';
    deltaCard.className = 'badge-card neutral';
    if (currBar) { currBar.style.backgroundColor = 'var(--accent)'; currBar.style.height = '100%'; }
    deltaMsg.textContent = 'Security posture is consistent with the historical baseline.';
  }

  /* 4. POLICY DRIFT SNAPSHOT */
  const govData = current.modelGov || [];
  const activeViolations = govData.filter(v => v["IMPACT VERDICT"]?.includes('Restricted')).length || 4;
  const totalObserved = govData.length || 22;

  setVal('declared-val', 0); // Hardcoded logic from Frame 3
  setVal('violations-val', activeViolations);
  setVal('unsupported-val', totalObserved);
  setPill('drift-status', activeViolations > 0 ? 'Drift Detected' : 'Nominal', activeViolations > 0 ? 'critical' : 'ok');

  const tbody = document.getElementById('drift-table-body');
  if (tbody) {
    tbody.innerHTML = '';
    const driftExamples = [
      { feature: 'FirstName', usage: 'Inference' },
      { feature: 'LastName',  usage: 'Inference' },
      { feature: 'Age',       usage: 'Inference' }
    ];
    driftExamples.forEach(row => {
      tbody.innerHTML += `<tr>
        <td><strong>${row.feature}</strong></td>
        <td>${row.usage}</td>
        <td><span class="badge-unsupported">Not Declared</span></td>
      </tr>`;
    });
  }

  /* 5. PRIORITY SIGNALS */
  const list = document.getElementById('signal-list');
  if (list) {
    list.innerHTML = `
      <li class="signal-item">
        <span class="signal-badge critical">Critical</span>
        <span class="signal-text">${modelRisks} unsigned Pickle / Joblib artifacts detected — remote code execution risk.</span>
      </li>
      <li class="signal-item">
        <span class="signal-badge high">High</span>
        <span class="signal-text">Policy drift: ${totalObserved} observed variables have no governance mapping.</span>
      </li>
      <li class="signal-item">
        <span class="signal-badge warning">Warning</span>
        <span class="signal-text">${endpointsCount} unique third-party AI egress destinations identified in network logs.</span>
      </li>
    `;
  }
}

/* ── APPSMITH INIT ───────────────────────────────────────── */
if (typeof appsmith !== 'undefined') {
  appsmith.onReady(updateDashboard);
  appsmith.onModelChange(updateDashboard);
} else {
  // Fallback for running outside of Appsmith environments
  window.addEventListener('DOMContentLoaded', updateDashboard);
}
